import { useState } from 'react';
import { ExternalLink } from 'lucide-react';

interface Product {
  name: string;
  color: string;
  tagline: string;
  url: string;
  accentClass: string;
  borderClass: string;
  bgClass: string;
  vision: string;
}

const products: Product[] = [
  {
    name: 'DD Red',
    color: 'red',
    tagline: 'The Execution Engine',
    url: 'https://dev-dash-red.vercel.app',
    accentClass: 'text-red-400',
    borderClass: 'border-red-500/30',
    bgClass: 'bg-red-500/10',
    vision: `# DD Red — The Execution Engine

> Your backlog works while you sleep.

## What It Is

DD Red is an AI agent execution platform that turns a project backlog into a running pipeline. Instead of treating issues as passive descriptions waiting for a human, DD Red treats them as dispatchable units of work — analyzed, decomposed, and executed by AI agents in sandboxed environments.

## The Problem

Developers maintain backlogs of hundreds of issues. Most sit untouched. The bottleneck isn't knowing *what* to do — it's having enough hands to do it. AI coding agents exist, but they operate one-at-a-time, require manual prompting, and don't understand your project's context.

## The Insight

An issue isn't just a description. With the right metadata — complexity estimate, affected files, dependency ordering, pre-instructions — it becomes a machine-executable work order. DD Red adds that metadata automatically, then dispatches agents to execute it.

## Core Loop

\`\`\`
Issue exists → Analyze complexity → Decompose into subtasks →
Generate pre-instructions → Dispatch agent(s) → Stream results →
Handle failures (retry with context) → PR lands → Close issue
\`\`\`

## Key Capabilities

### 1. Task Intelligence
- AI-powered complexity analysis (small / medium / large)
- Automatic subtask decomposition with dependency graphs
- Pre-instruction generation (agent-specific guidance per task)
- Affected file and module identification

### 2. Agent Dispatch
- Sandboxed execution (E2B, Railway workers)
- Rich context injection: project memory, README, task list, conventions
- Parallel execution of independent subtasks (worktree runs)
- Priority queue with concurrency management

### 3. Failure Feedback Loop
- Structured failure analysis with categorization
- Artifact preservation from failed runs (diffs, logs, rescue branches)
- Retry with accumulated failure context — agents learn from prior attempts
- Escalation when retry budget is exhausted

### 4. Campaign Execution
- Parent task → child subtasks → parallel agent dispatch
- Dependency-aware sequencing (task B waits for task A)
- Progress tracking across the full campaign
- Single PR or per-subtask PRs with configurable merge strategy

## What DD Red Is NOT

- **Not a task tracker.** GitHub Issues / Linear / Jira own the source of truth. DD Red syncs from them.
- **Not an AI coding assistant.** Claude Code, Cursor, Copilot are for interactive coding. DD Red is for batch execution.
- **Not a CI/CD pipeline.** GitHub Actions runs tests. DD Red runs the work that produces the code being tested.

## Target User

A developer or small team with a real backlog (50+ issues) who wants to parallelize execution. They already use GitHub Issues. They want to point DD Red at their repo and watch agents chew through the queue.

## Success Metric

Issues closed per week without a human writing code.

## Implementation Priorities

1. **Campaign dashboard** — visualize parent→child decomposition and execution status
2. **Dispatch controls** — one-click "run this issue" and "run all ready children"
3. **Execution stream** — real-time agent output with failure highlighting
4. **Failure triage** — categorized failures with one-click retry
5. **Backlog scanner** — surface agent-suitable issues from your existing backlog`,
  },
  {
    name: 'DD Yellow',
    color: 'yellow',
    tagline: 'The Context Layer',
    url: 'https://dev-dash-yellow.vercel.app',
    accentClass: 'text-amber-400',
    borderClass: 'border-amber-500/30',
    bgClass: 'bg-amber-500/10',
    vision: `# DD Yellow — The Context Layer

> Make any agent smarter about your codebase.

## What It Is

DD Yellow is the institutional memory for software projects. It captures architecture decisions, failure patterns, code conventions, and team knowledge — then makes that context available to any AI agent working on the codebase, regardless of which tool drives the session.

## The Problem

Every AI coding session starts from near-zero. The agent reads your README, maybe a rules file, and guesses at everything else. It doesn't know that you migrated from REST to GraphQL last month. It doesn't know the auth module is fragile. It doesn't know that the last three agents who touched the payment flow all hit the same race condition.

This knowledge exists — in Slack threads, PR reviews, postmortems, and developers' heads. But it's never structured, never accumulated, and never injected into agent context.

## The Insight

The bottleneck for AI agent quality isn't model capability — it's context. A mediocre model with rich project context outperforms a frontier model guessing blind. DD Yellow is the system that captures, structures, and delivers that context.

## Core Loop

\`\`\`
Work happens → Knowledge captured (auto + manual) →
Structured & indexed → Agent session starts →
Relevant context injected → Better output →
New learnings captured → Loop compounds
\`\`\`

## Key Capabilities

### 1. Knowledge Capture
- **Manual entries**: Architecture decisions, conventions, gotchas — written by humans
- **Failure mining**: Automatically extract lessons from failed agent runs
- **PR archaeology**: Distill patterns from merged PRs and code reviews
- **Session summaries**: Compress agent session transcripts into reusable context

### 2. Context Structure
- Project-scoped memory (per-repo knowledge)
- Cross-project memory (org-level patterns and preferences)
- Typed knowledge categories: architecture, conventions, failures, dependencies, patterns
- Temporal awareness: what's current vs. what's historical

### 3. Context Delivery
- **CLAUDE.md generation**: Auto-generate and maintain rules files from structured memory
- **Agent context building**: Synthesize relevant context for a specific task
- **MCP server**: Expose project memory as a tool any agent can query
- **API access**: Any tool, any workflow, same memory

### 4. Compounding Intelligence
- Agents that fail leave breadcrumbs for the next attempt
- Patterns detected across multiple sessions get promoted to conventions
- Stale knowledge detected and flagged for review
- Knowledge graph of how concepts relate across the codebase

## What DD Yellow Is NOT

- **Not an agent.** It doesn't write code. It makes agents that write code better.
- **Not a documentation tool.** Confluence is for human docs. DD Yellow is for machine-consumable project context.
- **Not a RAG system.** It's not vector search over your codebase. It's curated, structured knowledge that's always relevant.

## Target User

A developer or team that uses AI coding tools daily and is frustrated by how much context they have to re-explain every session. They want their agents to "just know" how the project works.

## Success Metric

Reduction in agent failures caused by missing context. Time saved not re-explaining project conventions.

## Implementation Priorities

1. **Memory explorer** — browse, edit, and organize project knowledge
2. **Context preview** — see exactly what context an agent would receive for a given task
3. **Failure-to-knowledge pipeline** — one-click "learn from this failure"
4. **CLAUDE.md sync** — generate and push rules files from structured memory
5. **MCP server endpoint** — expose memory as a tool for external agents`,
  },
  {
    name: 'DD Violet',
    color: 'violet',
    tagline: 'The Coordination Plane',
    url: 'https://dev-dash-violet.vercel.app',
    accentClass: 'text-violet-400',
    borderClass: 'border-violet-500/30',
    bgClass: 'bg-violet-500/10',
    vision: `# DD Violet — The Coordination Plane

> One team. Humans and agents. One backlog.

## What It Is

DD Violet is the coordination layer for engineering teams that deploy AI agents alongside human developers. It provides a unified board where human work and agent work are managed with the same primitives — routing, dependencies, conflict detection, review queues, and velocity tracking.

## The Problem

Today's AI coding tools are solo instruments. One developer, one agent, one task. But real engineering happens in teams: five developers and (increasingly) N agents, all working the same codebase. Nobody is solving the coordination problem:

- Who works on what? (human vs. agent assignment)
- What order? (dependencies across human and agent tasks)
- What conflicts? (two agents touching the same files)
- Who reviews? (agent output needs human eyes)
- What's the throughput? (unified velocity across all workers)

GitHub Projects tracks human work. Devin runs one agent. Nothing unifies the two.

## The Insight

Agents are team members, not tools. They need to be assigned work, have their conflicts managed, have their output reviewed, and have their throughput tracked — just like humans. The missing product is the coordination plane that treats humans and agents as interchangeable workers on a shared board.

## Core Loop

\`\`\`
Backlog exists → Triage (agent-suitable vs human-required) →
Route to worker (human or agent) → Monitor execution →
Detect conflicts → Route for review → Track velocity →
Retrospect & improve routing
\`\`\`

## Key Capabilities

### 1. Intelligent Routing
- Auto-classify tasks as agent-dispatchable vs human-required
- Complexity, ambiguity, and isolation scoring
- Load-balanced assignment across available workers (human + agent)
- Escalation paths: agent stuck → human notified → human takes over

### 2. Conflict Management
- File-level conflict detection across concurrent workers
- Automatic serialization when two workers target the same module
- Dependency-aware scheduling: task B waits for task A regardless of worker type
- Branch strategy management (per-task branches, merge ordering)

### 3. Review Pipeline
- Agent output automatically queued for human review
- Reviewer assignment based on code ownership and availability
- Review SLAs and aging alerts
- One-click approve/reject/retry with feedback

### 4. Unified Velocity
- Combined throughput: "47 tasks closed — 12 by humans, 35 by agents"
- Per-worker efficiency metrics (agents: success rate, retry rate; humans: cycle time)
- Team capacity planning: how many agents can we effectively deploy?
- Trend tracking: is adding more agents actually moving the needle?

### 5. Cross-Project Orchestration
- Plans spanning multiple repositories
- Dependency ordering across repos (API change before client update)
- Cross-project conflict detection
- Milestone tracking across the full engineering org

## What DD Violet Is NOT

- **Not a project management tool.** Linear and Jira own the backlog UI. DD Violet owns the coordination of who (human or agent) executes what.
- **Not an agent runner.** DD Red handles execution. DD Violet handles routing and coordination.
- **Not a code review tool.** GitHub PRs handle review mechanics. DD Violet handles review routing and tracking.

## Target User

An engineering team (5-20 developers) that has started using AI agents for real work and hit the coordination wall. They need visibility into what agents are doing, confidence that agents aren't stepping on each other, and proof that deploying agents is actually accelerating their throughput.

## Success Metric

Team velocity (tasks closed per sprint) with N agents deployed vs. without. Review queue aging (how fast does agent output get reviewed?).

## Implementation Priorities

1. **Team board** — unified view of all work, colored by worker type (human/agent)
2. **Routing dashboard** — triage backlog into agent-suitable vs human-required
3. **Review inbox** — agent PRs awaiting human review, sorted by age and priority
4. **Velocity charts** — human vs agent throughput over time
5. **Conflict alerts** — real-time warnings when workers target overlapping files`,
  },
];

function renderMarkdown(md: string, accentClass: string): JSX.Element[] {
  const lines = md.split('\n');
  const elements: JSX.Element[] = [];
  let inCodeBlock = false;
  let codeLines: string[] = [];
  let inList = false;
  let listItems: JSX.Element[] = [];

  const flushList = () => {
    if (inList && listItems.length > 0) {
      elements.push(<ul key={`ul-${elements.length}`} className="space-y-1 mb-4">{listItems}</ul>);
      listItems = [];
      inList = false;
    }
  };

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    if (line.startsWith('```')) {
      if (inCodeBlock) {
        flushList();
        elements.push(
          <pre key={`code-${i}`} className="bg-theme-bg border border-theme-border rounded-lg p-4 mb-4 overflow-x-auto text-sm font-mono text-theme-muted">
            {codeLines.join('\n')}
          </pre>
        );
        codeLines = [];
        inCodeBlock = false;
      } else {
        flushList();
        inCodeBlock = true;
      }
      continue;
    }

    if (inCodeBlock) {
      codeLines.push(line);
      continue;
    }

    if (line.trim() === '') {
      flushList();
      continue;
    }

    if (line.startsWith('# ')) {
      flushList();
      continue; // skip h1 — we render the title in the card header
    }

    if (line.startsWith('> ')) {
      flushList();
      elements.push(
        <blockquote key={`bq-${i}`} className={`border-l-2 ${accentClass.replace('text-', 'border-')} pl-4 mb-4 italic text-theme-muted`}>
          {line.slice(2)}
        </blockquote>
      );
      continue;
    }

    if (line.startsWith('## ')) {
      flushList();
      elements.push(
        <h2 key={`h2-${i}`} className="text-lg font-semibold text-theme-text mt-6 mb-3">
          {line.slice(3)}
        </h2>
      );
      continue;
    }

    if (line.startsWith('### ')) {
      flushList();
      elements.push(
        <h3 key={`h3-${i}`} className="text-sm font-semibold text-theme-text mt-4 mb-2">
          {line.slice(4)}
        </h3>
      );
      continue;
    }

    if (line.startsWith('- ')) {
      inList = true;
      const text = line.slice(2);
      const boldMatch = text.match(/^\*\*(.+?)\*\*(.*)$/);
      listItems.push(
        <li key={`li-${i}`} className="text-sm text-theme-muted flex gap-2">
          <span className={`${accentClass} mt-1.5 flex-shrink-0`}>&#8226;</span>
          <span>
            {boldMatch ? (
              <><strong className="text-theme-text">{boldMatch[1]}</strong>{boldMatch[2]}</>
            ) : (
              formatInline(text)
            )}
          </span>
        </li>
      );
      continue;
    }

    if (/^\d+\.\s/.test(line)) {
      inList = true;
      const text = line.replace(/^\d+\.\s/, '');
      const boldMatch = text.match(/^\*\*(.+?)\*\*(.*)$/);
      listItems.push(
        <li key={`li-${i}`} className="text-sm text-theme-muted flex gap-2">
          <span className={`${accentClass} mt-0 flex-shrink-0 font-mono text-xs`}>{line.match(/^\d+/)![0]}.</span>
          <span>
            {boldMatch ? (
              <><strong className="text-theme-text">{boldMatch[1]}</strong>{boldMatch[2]}</>
            ) : (
              formatInline(text)
            )}
          </span>
        </li>
      );
      continue;
    }

    flushList();
    elements.push(
      <p key={`p-${i}`} className="text-sm text-theme-muted mb-3 leading-relaxed">
        {formatInline(line)}
      </p>
    );
  }

  flushList();
  return elements;
}

function formatInline(text: string): (string | JSX.Element)[] {
  const parts: (string | JSX.Element)[] = [];
  const regex = /\*\*(.+?)\*\*|`(.+?)`|\*(.+?)\*/g;
  let lastIndex = 0;
  let match;

  while ((match = regex.exec(text)) !== null) {
    if (match.index > lastIndex) {
      parts.push(text.slice(lastIndex, match.index));
    }
    if (match[1]) {
      parts.push(<strong key={match.index} className="text-theme-text font-medium">{match[1]}</strong>);
    } else if (match[2]) {
      parts.push(<code key={match.index} className="px-1.5 py-0.5 bg-theme-bg rounded text-xs font-mono">{match[2]}</code>);
    } else if (match[3]) {
      parts.push(<em key={match.index}>{match[3]}</em>);
    }
    lastIndex = match.index + match[0].length;
  }

  if (lastIndex < text.length) {
    parts.push(text.slice(lastIndex));
  }

  return parts;
}

export function Products() {
  const [selected, setSelected] = useState<number>(0);
  const product = products[selected];

  return (
    <div className="h-full flex flex-col">
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold text-theme-text">Product Variants</h1>
      </div>

      {/* Tab bar */}
      <div className="flex gap-2 mb-6">
        {products.map((p, i) => (
          <button
            key={p.name}
            onClick={() => setSelected(i)}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              selected === i
                ? `${p.bgClass} ${p.accentClass} border ${p.borderClass}`
                : 'text-theme-muted hover:text-theme-text bg-theme-surface border border-theme-border'
            }`}
          >
            {p.name}
          </button>
        ))}
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto">
        <div className="bg-theme-surface border border-theme-border rounded-xl">
          {/* Header */}
          <div className={`p-6 border-b border-theme-border flex items-center justify-between`}>
            <div>
              <h2 className={`text-xl font-bold ${product.accentClass}`}>
                {product.name} — {product.tagline}
              </h2>
              <a
                href={product.url}
                target="_blank"
                rel="noopener noreferrer"
                className={`inline-flex items-center gap-1.5 mt-2 text-sm ${product.accentClass} hover:underline`}
              >
                {product.url}
                <ExternalLink className="w-3.5 h-3.5" />
              </a>
            </div>
            <a
              href={product.url}
              target="_blank"
              rel="noopener noreferrer"
              className={`px-4 py-2 rounded-lg text-sm font-medium ${product.bgClass} ${product.accentClass} border ${product.borderClass} hover:opacity-80 transition-opacity flex items-center gap-2`}
            >
              Visit Site
              <ExternalLink className="w-4 h-4" />
            </a>
          </div>

          {/* Markdown body */}
          <div className="p-6 max-w-3xl">
            {renderMarkdown(product.vision, product.accentClass)}
          </div>
        </div>
      </div>
    </div>
  );
}

