import React, { useState } from 'react';
import { FlaskConical } from 'lucide-react';
import { useProjects } from '../hooks/useProjects';
import { TaskCentricView } from '../components/lab/TaskCentricView';
import { CommandCenterView } from '../components/lab/CommandCenterView';
import { WorkflowPipelineView } from '../components/lab/WorkflowPipelineView';
import { DependencyGraphView } from '../components/lab/DependencyGraphView';
import { AgentTimelineView } from '../components/lab/AgentTimelineView';
import { DevDashCommandCenter } from '../components/lab/DevDashCommandCenter';
import { RetroHeartbeat90s } from '../components/lab/RetroHeartbeat90s';

type Experiment = 'task-centric' | 'command-center' | 'pipeline' | 'dep-graph' | 'agent-timeline' | 'dash-cc' | 'retro-90s';

const experiments: { id: Experiment; label: string }[] = [
  { id: 'task-centric', label: 'Task-Centric' },
  { id: 'command-center', label: 'Command Center' },
  { id: 'pipeline', label: 'Pipeline' },
  { id: 'dep-graph', label: 'Dep Graph' },
  { id: 'agent-timeline', label: 'Agent Timeline' },
  { id: 'dash-cc', label: 'Command HQ' },
  { id: 'retro-90s', label: '90s Heartbeat' },
];

export function UILab() {
  const { data: projects } = useProjects();
  const [projectId, setProjectId] = useState<string>('');
  const [activeExperiment, setActiveExperiment] = useState<Experiment>('task-centric');

  // Auto-select first project if none selected
  React.useEffect(() => {
    if (!projectId && projects?.length) {
      setProjectId(projects[0].id);
    }
  }, [projects, projectId]);

  return (
    <div className="flex-1 flex flex-col min-h-0">
      {/* Header */}
      <div className="px-6 pt-6 pb-0">
        <div className="flex items-center gap-3 mb-1">
          <FlaskConical className="w-6 h-6 text-brand-primary" />
          <h1 className="text-2xl font-bold text-theme-text">UI Lab</h1>
        </div>
        <p className="text-sm text-theme-muted mb-4">
          Experimental project workflow views. Same data, different layouts.
        </p>

        {/* Project + Experiment selectors */}
        <div className="flex gap-3 mb-4">
          <select
            value={projectId}
            onChange={(e) => setProjectId(e.target.value)}
            className="bg-theme-surface border border-theme-border rounded-lg px-3 py-2 text-sm text-theme-text focus:outline-none focus:ring-2 focus:ring-brand-primary focus:border-transparent"
          >
            <option value="">Select a project...</option>
            {projects?.map((p) => (
              <option key={p.id} value={p.id}>
                {p.name}
              </option>
            ))}
          </select>

          <select
            value={activeExperiment}
            onChange={(e) => setActiveExperiment(e.target.value as Experiment)}
            className="bg-theme-surface border border-theme-border rounded-lg px-3 py-2 text-sm text-theme-text focus:outline-none focus:ring-2 focus:ring-brand-primary focus:border-transparent"
          >
            {experiments.map((exp) => (
              <option key={exp.id} value={exp.id}>
                {exp.label}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Active experiment */}
      <div className="flex-1 min-h-0 overflow-hidden">
        {!projectId ? (
