import React, { useMemo, useState } from 'react';
import { clsx } from 'clsx';
import {
  Flame,
  ChevronDown,
  ChevronRight,
  FileCode,
  AlertTriangle,
  CheckCircle2,
  ShieldAlert,
  Zap,
  Circle,
  Loader2,
  Search,
  ArrowUpDown,
  Info,
  Target,
  BookOpen,
  TestTube2,
  Shield,
  GitBranch,
} from 'lucide-react';
import { useBeads } from '../../hooks/useBeads';
import type { Bead, BeadStatus } from '../../types';

interface BurnScoreExplorerProps {
  projectId: string;
}

type SortField = 'automability' | 'complexity' | 'instructionQuality' | 'scopeBoundedness' | 'testability' | 'riskLevel' | 'dependencyClarity' | 'subject';
type SortDir = 'asc' | 'desc';
type FilterGrade = 'all' | 'A' | 'B' | 'C' | 'D' | 'F' | 'unscored';
type FilterStatus = 'all' | 'pending' | 'ready' | 'in_progress' | 'blocked' | 'completed' | 'failed';

const gradeColors: Record<string, string> = {
  A: 'bg-green-500/20 text-green-400 border-green-500/40',
  B: 'bg-blue-500/20 text-blue-400 border-blue-500/40',
  C: 'bg-yellow-500/20 text-yellow-400 border-yellow-500/40',
  D: 'bg-orange-500/20 text-orange-400 border-orange-500/40',
  F: 'bg-red-500/20 text-red-400 border-red-500/40',
};

const factorMeta: Record<string, { label: string; icon: React.ReactNode; hint: string }> = {
  instructionQuality: {
    label: 'Instructions',
    icon: <BookOpen className="w-3.5 h-3.5" />,
    hint: 'Add file paths, code snippets, line numbers, or before/after examples to pre-instructions',
  },
  scopeBoundedness: {
    label: 'Scope',
    icon: <Target className="w-3.5 h-3.5" />,
    hint: 'Reduce affected files or split into smaller subtasks',
  },
  testability: {
    label: 'Testability',
    icon: <TestTube2 className="w-3.5 h-3.5" />,
    hint: 'Reference test files, add npm test commands, or mention specific test cases',
  },
  riskLevel: {
    label: 'Risk (inv)',
    icon: <Shield className="w-3.5 h-3.5" />,
    hint: 'Make this a leaf task with explicit dependencies and small complexity',
  },
  dependencyClarity: {
    label: 'Dependencies',
    icon: <GitBranch className="w-3.5 h-3.5" />,
    hint: 'Add blocked_by/blocks relationships and organize under a parent task',
  },
};

const statusIcon = (status: BeadStatus) => {
  switch (status) {
    case 'completed': return <CheckCircle2 className="w-3.5 h-3.5 text-green-400" />;
    case 'in_progress': return <Loader2 className="w-3.5 h-3.5 text-brand-primary animate-spin" />;
    case 'ready': return <Zap className="w-3.5 h-3.5 text-emerald-400" />;
    case 'blocked': return <ShieldAlert className="w-3.5 h-3.5 text-amber-400" />;
    case 'failed': return <AlertTriangle className="w-3.5 h-3.5 text-red-500" />;
    default: return <Circle className="w-3.5 h-3.5 text-theme-muted" />;
  }
};

function FactorBar({ value, max = 20 }: { value: number; max?: number }) {
  const pct = Math.round((value / max) * 100);
  const color = pct >= 75 ? 'bg-green-500' : pct >= 50 ? 'bg-blue-500' : pct >= 25 ? 'bg-yellow-500' : 'bg-red-500';
  return (
    <div className="flex items-center gap-2 flex-1">
      <div className="flex-1 h-2 bg-theme-bg rounded-full overflow-hidden">
        <div className={clsx('h-full rounded-full transition-all', color)} style={{ width: `${pct}%` }} />
      </div>
      <span className="text-xs text-theme-muted w-6 text-right font-mono">{value}</span>
    </div>
  );
}

function ScoreBreakdown({ bead, expanded }: { bead: Bead; expanded: boolean }) {
  if (!expanded) return null;

  const factors = bead.burnScores;
  const analysis = bead.analysisResult;
  const readiness = bead.readinessResult;

  return (
    <div className="border-t border-theme-border bg-theme-bg/50 px-4 py-3 space-y-4">
      {/* Factors */}
      {factors && (
        <div>
          <h4 className="text-xs font-semibold text-theme-muted uppercase tracking-wider mb-2">Burn Score Factors</h4>
          <div className="space-y-1.5">
            {(Object.keys(factorMeta) as Array<keyof typeof factorMeta>).map((key) => {
              const meta = factorMeta[key];
              const val = factors[key as keyof typeof factors];
              const isLow = val < 10;
              return (
                <div key={key} className="flex items-center gap-2">
                  <span className={clsx('flex items-center gap-1.5 w-28 text-xs', isLow ? 'text-amber-400' : 'text-theme-muted')}>
                    {meta.icon} {meta.label}
                  </span>
                  <FactorBar value={val} />
                  {isLow && (
                    <span className="text-xs text-amber-400/70 flex items-center gap-1" title={meta.hint}>
                      <Info className="w-3 h-3" />
                    </span>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Analysis summary */}
      {analysis && (
        <div>
          <h4 className="text-xs font-semibold text-theme-muted uppercase tracking-wider mb-2">Analysis</h4>
          <div className="text-xs text-theme-muted space-y-1">
            {analysis.affectedFiles && analysis.affectedFiles.length > 0 && (
              <div className="flex items-start gap-2">
                <FileCode className="w-3.5 h-3.5 mt-0.5 flex-shrink-0" />
                <span>{analysis.affectedFiles.length} file{analysis.affectedFiles.length !== 1 ? 's' : ''}: {analysis.affectedFiles.slice(0, 4).join(', ')}{analysis.affectedFiles.length > 4 ? ` +${analysis.affectedFiles.length - 4}` : ''}</span>
              </div>
            )}
            {analysis.shouldSubdivide && (
              <div className="flex items-center gap-2 text-amber-400">
                <AlertTriangle className="w-3.5 h-3.5" />
                <span>Recommends subdivision into {analysis.suggestedSubtasks?.length ?? '?'} subtasks</span>
              </div>
            )}
            {analysis.reasoning && (
              <p className="text-theme-muted/80 mt-1 leading-relaxed">{analysis.reasoning}</p>
            )}
          </div>
        </div>
      )}

      {/* Readiness evaluation */}
      {readiness && (
        <div>
          <h4 className="text-xs font-semibold text-theme-muted uppercase tracking-wider mb-2">Readiness</h4>
          <div className="space-y-1">
            {readiness.reasons.map((r, i) => (
              <div key={i} className={clsx('text-xs flex items-center gap-1.5', readiness.viable ? 'text-green-400/80' : 'text-red-400/80')}>
                {readiness.viable ? <CheckCircle2 className="w-3 h-3" /> : <AlertTriangle className="w-3 h-3" />}
                {r}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Low-factor hints */}
      {factors && (
        <div>
          {(Object.keys(factorMeta) as Array<keyof typeof factorMeta>)
            .filter((key) => factors[key as keyof typeof factors] < 10)
            .map((key) => (
              <div key={key} className="flex items-start gap-2 text-xs text-amber-400/80 mt-1">
                <Info className="w-3 h-3 mt-0.5 flex-shrink-0" />
                <span><strong>{factorMeta[key].label}:</strong> {factorMeta[key].hint}</span>
              </div>
            ))}
        </div>
      )}
    </div>
  );
}

export function BurnScoreExplorer({ projectId }: BurnScoreExplorerProps) {
  const { data: beads = [] } = useBeads(projectId);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [search, setSearch] = useState('');
  const [sortField, setSortField] = useState<SortField>('automability');
  const [sortDir, setSortDir] = useState<SortDir>('desc');
  const [filterGrade, setFilterGrade] = useState<FilterGrade>('all');
  const [filterStatus, setFilterStatus] = useState<FilterStatus>('all');

  const toggleSort = (field: SortField) => {
    if (sortField === field) {
      setSortDir((d) => (d === 'asc' ? 'desc' : 'asc'));
    } else {
      setSortField(field);
      setSortDir('desc');
    }
  };

  const filtered = useMemo(() => {
    let items = [...beads];

    // Search
    if (search) {
      const q = search.toLowerCase();
      items = items.filter((b) => b.subject.toLowerCase().includes(q) || b.description?.toLowerCase().includes(q));
    }

    // Grade filter
    if (filterGrade === 'unscored') {
      items = items.filter((b) => !b.automabilityGrade);
    } else if (filterGrade !== 'all') {
      items = items.filter((b) => b.automabilityGrade === filterGrade);
    }

    // Status filter
    if (filterStatus !== 'all') {
      items = items.filter((b) => b.status === filterStatus);
    }

    // Sort
    const dir = sortDir === 'asc' ? 1 : -1;
    items.sort((a, b) => {
      let av: number | string = 0;
      let bv: number | string = 0;
      if (sortField === 'automability') {
        av = a.automabilityScore ?? -1;
        bv = b.automabilityScore ?? -1;
      } else if (sortField === 'complexity') {
        av = a.complexityScore ?? -1;
        bv = b.complexityScore ?? -1;
      } else if (sortField === 'subject') {
        av = a.subject.toLowerCase();
        bv = b.subject.toLowerCase();
      } else {
        // Factor sort
        av = a.burnScores?.[sortField as keyof NonNullable<Bead['burnScores']>] ?? -1;
        bv = b.burnScores?.[sortField as keyof NonNullable<Bead['burnScores']>] ?? -1;
      }
      if (av < bv) return -1 * dir;
      if (av > bv) return 1 * dir;
      return 0;
    });

    return items;
  }, [beads, search, sortField, sortDir, filterGrade, filterStatus]);

  // Stats
  const stats = useMemo(() => {
    const scored = beads.filter((b) => b.automabilityGrade);
    const grades: Record<string, number> = { A: 0, B: 0, C: 0, D: 0, F: 0 };
    scored.forEach((b) => { if (b.automabilityGrade) grades[b.automabilityGrade] = (grades[b.automabilityGrade] || 0) + 1; });
    const ready = beads.filter((b) => b.status === 'ready').length;
    const avgScore = scored.length > 0 ? Math.round(scored.reduce((s, b) => s + (b.automabilityScore ?? 0), 0) / scored.length) : 0;
    return { total: beads.length, scored: scored.length, unscored: beads.length - scored.length, grades, ready, avgScore };
  }, [beads]);

  return (
    <div className="flex flex-col h-full px-6 pb-6">
      {/* Stats bar */}
      <div className="flex items-center gap-4 py-3 border-b border-theme-border mb-3 flex-wrap">
        <div className="flex items-center gap-2">
          <Flame className="w-4 h-4 text-red-400" />
          <span className="text-sm font-medium text-theme-text">Burn Score Explorer</span>
        </div>
        <div className="flex items-center gap-3 text-xs text-theme-muted">
          <span>{stats.total} tasks</span>
          <span className="text-theme-border">|</span>
          <span>{stats.scored} scored</span>
          <span className="text-theme-border">|</span>
          <span>{stats.unscored} unscored</span>
          <span className="text-theme-border">|</span>
          <span className="text-emerald-400">{stats.ready} ready</span>
          <span className="text-theme-border">|</span>
          <span>avg score: <strong className="text-theme-text">{stats.avgScore}</strong></span>
        </div>
        <div className="flex items-center gap-2 ml-auto">
          {(['A', 'B', 'C', 'D', 'F'] as const).map((g) => (
            <span key={g} className={clsx('text-xs font-mono px-1.5 py-0.5 rounded border', gradeColors[g])}>
              {g}: {stats.grades[g]}
            </span>
          ))}
        </div>
      </div>

      {/* Filters */}
      <div className="flex items-center gap-3 mb-3 flex-wrap">
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-2.5 top-2 w-3.5 h-3.5 text-theme-muted" />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search tasks..."
            className="w-full pl-8 pr-3 py-1.5 bg-theme-surface border border-theme-border rounded-lg text-sm text-theme-text placeholder-theme-muted focus:outline-none focus:ring-1 focus:ring-brand-primary"
          />
        </div>
        <select
          value={filterGrade}
          onChange={(e) => setFilterGrade(e.target.value as FilterGrade)}
          className="bg-theme-surface border border-theme-border rounded-lg px-2 py-1.5 text-xs text-theme-text"
        >
          <option value="all">All grades</option>
          <option value="A">Grade A</option>
          <option value="B">Grade B</option>
          <option value="C">Grade C</option>
          <option value="D">Grade D</option>
          <option value="F">Grade F</option>
          <option value="unscored">Unscored</option>
        </select>
        <select
          value={filterStatus}
          onChange={(e) => setFilterStatus(e.target.value as FilterStatus)}
          className="bg-theme-surface border border-theme-border rounded-lg px-2 py-1.5 text-xs text-theme-text"
        >
          <option value="all">All statuses</option>
          <option value="pending">Pending</option>
          <option value="ready">Ready</option>
          <option value="in_progress">In Progress</option>
          <option value="blocked">Blocked</option>
          <option value="completed">Completed</option>
          <option value="failed">Failed</option>
        </select>
        <span className="text-xs text-theme-muted">{filtered.length} shown</span>
      </div>

      {/* Column headers */}
      <div className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-theme-muted border-b border-theme-border">
        <span className="w-5" />
        <span className="w-5" />
        <button onClick={() => toggleSort('subject')} className="flex-1 flex items-center gap-1 hover:text-theme-text text-left">
          Task {sortField === 'subject' && <ArrowUpDown className="w-3 h-3" />}
        </button>
        <button onClick={() => toggleSort('automability')} className={clsx('w-16 text-center hover:text-theme-text', sortField === 'automability' && 'text-theme-text')}>
          Score {sortField === 'automability' && <ArrowUpDown className="w-3 h-3 inline" />}
        </button>
        <button onClick={() => toggleSort('complexity')} className={clsx('w-12 text-center hover:text-theme-text', sortField === 'complexity' && 'text-theme-text')}>
          Cmplx {sortField === 'complexity' && <ArrowUpDown className="w-3 h-3 inline" />}
        </button>
        {(Object.keys(factorMeta) as Array<keyof typeof factorMeta>).map((key) => (
          <button
            key={key}
            onClick={() => toggleSort(key as SortField)}
            className={clsx('w-16 text-center hover:text-theme-text', sortField === key && 'text-theme-text')}
            title={factorMeta[key].label}
          >
            {factorMeta[key].label.slice(0, 5)} {sortField === key && <ArrowUpDown className="w-3 h-3 inline" />}
          </button>
        ))}
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto">
        {filtered.length === 0 ? (
          <div className="flex items-center justify-center h-32 text-sm text-theme-muted">
            {beads.length === 0 ? 'No tasks in this project.' : 'No tasks match filters.'}
          </div>
        ) : (
          filtered.map((bead) => {
            const isExpanded = expandedId === bead.id;
            const hasScores = !!bead.burnScores;
            return (
              <div key={bead.id} className={clsx('border-b border-theme-border/50', isExpanded && 'bg-theme-surface/50')}>
                <button
                  onClick={() => setExpandedId(isExpanded ? null : bead.id)}
                  className="w-full flex items-center gap-2 px-3 py-2 hover:bg-theme-surface/30 transition-colors text-left"
                >
                  {/* Expand chevron */}
                  <span className="w-5 flex-shrink-0 text-theme-muted">
                    {hasScores ? (
                      isExpanded ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />
                    ) : (
                      <span className="w-3.5" />
                    )}
                  </span>

                  {/* Status */}
                  <span className="w-5 flex-shrink-0">{statusIcon(bead.status)}</span>

                  {/* Subject */}
                  <span className="flex-1 text-sm text-theme-text truncate">{bead.subject}</span>

                  {/* Grade + Score */}
                  <span className="w-16 text-center">
                    {bead.automabilityGrade ? (
                      <span className={clsx('inline-flex items-center gap-1 text-xs font-mono px-1.5 py-0.5 rounded border', gradeColors[bead.automabilityGrade])}>
                        {bead.automabilityGrade}
                        <span className="text-[10px] opacity-70">{bead.automabilityScore}</span>
                      </span>
                    ) : (
                      <span className="text-xs text-theme-muted">--</span>
                    )}
                  </span>

                  {/* Complexity */}
                  <span className="w-12 text-center">
                    {bead.complexityScore != null ? (
                      <span className={clsx(
                        'text-xs font-mono px-1.5 py-0.5 rounded',
                        bead.complexityScore <= 4 ? 'text-green-400 bg-green-500/10' :
                        bead.complexityScore <= 8 ? 'text-yellow-400 bg-yellow-500/10' :
                        'text-red-400 bg-red-500/10'
                      )}>
                        {bead.complexityScore}
                      </span>
                    ) : (
                      <span className="text-xs text-theme-muted">--</span>
                    )}
                  </span>

                  {/* Factor mini-bars */}
                  {(Object.keys(factorMeta) as Array<keyof typeof factorMeta>).map((key) => {
                    const val = bead.burnScores?.[key as keyof NonNullable<Bead['burnScores']>];
                    return (
                      <span key={key} className="w-16 flex-shrink-0">
                        {val != null ? (
                          <div className="flex items-center gap-1">
                            <div className="flex-1 h-1.5 bg-theme-bg rounded-full overflow-hidden">
                              <div
                                className={clsx(
                                  'h-full rounded-full',
                                  val >= 15 ? 'bg-green-500' : val >= 10 ? 'bg-blue-500' : val >= 5 ? 'bg-yellow-500' : 'bg-red-500'
                                )}
                                style={{ width: `${(val / 20) * 100}%` }}
                              />
                            </div>
                            <span className="text-[10px] text-theme-muted font-mono w-4 text-right">{val}</span>
                          </div>
                        ) : (
                          <span className="text-[10px] text-theme-muted text-center block">--</span>
                        )}
                      </span>
                    );
                  })}
                </button>

                <ScoreBreakdown bead={bead} expanded={isExpanded} />
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}

