import React, { useState } from 'react';
import { FlaskConical } from 'lucide-react';
import { useProjects } from '../hooks/useProjects';
import { TaskCentricView } from '../components/lab/TaskCentricView';
import { CommandCenterView } from '../components/lab/CommandCenterView';
import { WorkflowPipelineView } from '../components/lab/WorkflowPipelineView';
import { DependencyGraphView } from '../components/lab/DependencyGraphView';
import { AgentTimelineView } from '../components/lab/AgentTimelineView';
